import{_ as e,c as a,o as i,ag as o}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Image Swatch Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/image-swatch.md","filePath":"fields/image-swatch.md","lastUpdated":null}'),l={name:"fields/image-swatch.md"};function s(n,t,r,h,d,c){return i(),a("div",null,t[0]||(t[0]=[o('<h1 id="image-swatch-field" tabindex="-1">Image Swatch Field <a class="header-anchor" href="#image-swatch-field" aria-label="Permalink to &quot;Image Swatch Field&quot;">​</a></h1><p>The <strong>Image Swatch</strong> field presents options as clickable thumbnail images instead of text labels. This is highly effective for visual products where a picture communicates the option far better than words.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Selecting a fabric pattern or textile print</li><li>Choosing a specific design, logo, or illustration to be printed</li><li>Selecting a product style or shape visually</li><li>Choosing a material texture (e.g., leather grain, wood finish)</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add an Image Swatch field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the swatch grid (e.g., &quot;Choose Your Pattern&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the swatches.</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must select one swatch before adding the product to the cart.</td></tr></tbody></table><h3 id="display-style" tabindex="-1">Display Style <a class="header-anchor" href="#display-style" aria-label="Permalink to &quot;Display Style&quot;">​</a></h3><p>You can choose how the swatch options are rendered on the frontend:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Style</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Swatch Only</strong></td><td style="text-align:left;">Shows just the image thumbnail. Clean and minimal.</td></tr><tr><td style="text-align:left;"><strong>Swatch + Label</strong></td><td style="text-align:left;">Shows the image thumbnail with the choice label text below it. Useful when images alone might be ambiguous.</td></tr></tbody></table><h3 id="choices-options" tabindex="-1">Choices (Options) <a class="header-anchor" href="#choices-options" aria-label="Permalink to &quot;Choices (Options)&quot;">​</a></h3><p>You must define at least one choice. Each choice has the following columns:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Image</strong></td><td style="text-align:left;">Click the image placeholder to open the WordPress Media Library and select an image. The thumbnail version of the image is used for the swatch.</td></tr><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The text identifying this choice (e.g., &quot;Floral Print&quot;). The <strong>Value</strong> is automatically generated from the label.</td></tr><tr><td style="text-align:left;"><strong>Price</strong></td><td style="text-align:left;">The numeric amount to add to the product price when this swatch is selected. Only visible when Price Type is not &quot;No Price&quot;.</td></tr><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">How this choice affects pricing. Options: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. Each choice can have its own independent price type.</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">Additional shipping weight to add when this choice is selected.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The <strong>size and border-radius</strong> of image swatches are configured globally in <strong>WooCommerce &gt; Settings &gt; OptionBay</strong>. Use the &quot;Image Swatch Size&quot; and &quot;Image Swatch Radius&quot; settings to match your theme&#39;s aesthetic.</p></div><p>You can add new choices using the <strong>+ Add Choice</strong> button and remove them using the trash icon.</p><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Choose Your Pattern&quot; image swatch only when the customer selects &quot;Custom Fabric&quot; from a material dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',19)]))}const m=e(l,[["render",s]]);export{u as __pageData,m as default};
